// Shared route manifest + helpers for the QA harness.
//
// This is the single source of truth every QA script crawls. The current site
// is a single page ("/"); Sprint 02 splits it into a real router and MUST keep
// this array in sync with the router (one ROUTES entry per navigable path).
//
// Each route:
//   path         URL path to visit (joined onto DEV_URL)
//   name         filesystem-safe tag for screenshot folders
//   ownedIds     section ids this route is expected to render (used by future
//                route-aware checks; empty allowed)
//   showpiece    CSS selector of a GL/scrub showpiece on the route, or null.
//                walkthrough/verify measure draw calls only where this is set.
//   mobileStatic true => mobile/reduced-motion must render a designed static
//                final state (never blank), per scar #8.
//   legacy       true ONLY for the pre-rebuild site: axe a11y/contrast audit is
//                logged informationally instead of gating. Rebuilt routes
//                (Sprint 02 onward) must NOT carry this flag — they gate hard
//                on serious/critical axe violations incl. color-contrast.
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

export const DEV_URL = "http://localhost:5173";

export const ROUTES = [
  {
    path: "/",
    name: "home",
    ownedIds: ["services", "case-studies", "process", "team", "contact", "newsletter"],
    // Current site mounts a WebGL hero orb on desktop (lazy ./hero/HeroCanvas),
    // gated off on mobile + reduced-motion. Setting the showpiece lets verify
    // allow GL bytes on desktop while still enforcing zero-GL on mobile/reduced.
    // Sprint 10/11 repoint this to the new hero/pipeline canvas selector.
    showpiece: "#hero canvas",
    mobileStatic: true,
    legacy: true,
  },
];

// /tmp/shots/<tag>/  — walkthrough signature shots.
// /tmp/shots-dense/<route-name>/ — dense scroll shots.
export function SHOTS_DIR(tag = "manual") {
  return path.join("/tmp/shots", tag);
}
export function DENSE_DIR(routeName) {
  return path.join("/tmp/shots-dense", routeName);
}

export function routeUrl(route, query = "") {
  const base = DEV_URL + route.path;
  if (!query) return base;
  return base + (route.path.includes("?") ? "&" : "?") + query.replace(/^\?/, "");
}

// Robust Chromium/Chrome resolver. Order:
//   1. $CHROME_PATH (explicit override)
//   2. playwright-core's bundled chromium.executablePath() if it resolves
//   3. common macOS install paths (Chrome for Testing, then Google Chrome)
// Exits with a clear, actionable message if none is found.
export async function resolveChrome() {
  const fromEnv = process.env.CHROME_PATH;
  if (fromEnv && fs.existsSync(fromEnv)) return fromEnv;

  try {
    const { chromium } = await import("playwright-core");
    const p = chromium.executablePath();
    if (p && fs.existsSync(p)) return p;
  } catch {
    // playwright-core absent or no browser downloaded — fall through to paths.
  }

  const candidates = [
    "/Applications/Google Chrome for Testing.app/Contents/MacOS/Google Chrome for Testing",
    `${process.env.HOME || ""}/Applications/Google Chrome for Testing.app/Contents/MacOS/Google Chrome for Testing`,
    "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
    "/Applications/Chromium.app/Contents/MacOS/Chromium",
    "/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge",
  ];
  for (const c of candidates) {
    if (c && fs.existsSync(c)) return c;
  }

  console.error(
    [
      "FATAL: no Chromium/Chrome executable found.",
      "Tried, in order:",
      "  1. $CHROME_PATH (env override)",
      "  2. playwright-core chromium.executablePath()",
      "  3. common macOS install paths",
      "",
      "Fix one of:",
      "  - export CHROME_PATH=/path/to/chrome",
      "  - npx playwright install chromium   (downloads the bundled build)",
      "  - install Google Chrome",
    ].join("\n")
  );
  process.exit(2);
}

// Tiny arg parser: --tag=foo --route=/ ?skippreload-style flags.
export function parseArgs(argv = process.argv.slice(2)) {
  const out = { _: [] };
  for (const a of argv) {
    const m = a.match(/^--([^=]+)(?:=(.*))?$/);
    if (m) out[m[1]] = m[2] === undefined ? true : m[2];
    else out._.push(a);
  }
  return out;
}

// Resolve the cwd's repo root (two levels up from scripts/qa/).
export function repoRoot() {
  const here = path.dirname(fileURLToPath(import.meta.url));
  return path.resolve(here, "..", "..");
}

