1	// verify.mjs — route-driven assertion suite (v0).
2	//
3	// Boots playwright-core against the running dev server (:5173) and asserts the
4	// invariants that must hold on every build. v0 targets the CURRENT single-page
5	// site; sprints extend ROUTES + add route-aware checks via the check() harness.
6	//
7	// Usage:
8	//   node scripts/qa/verify.mjs               full suite, all ROUTES
9	//   node scripts/qa/verify.mjs --route=/     restrict to one route
10	//   node scripts/qa/verify.mjs --skippreload pass ?skippreload to every load
11	//
12	// Exit 0 only if every check passes; non-zero with a failure list otherwise.
13	import fs from "fs";
14	import { chromium } from "playwright-core";
15	import { ROUTES, DEV_URL, resolveChrome, parseArgs } from "./routes.mjs";
16	
17	// axe-core source, injected per page for the a11y/contrast audit (WCAG 2 A+AA).
18	const AXE_SOURCE = fs.readFileSync(
19	  new URL("../../node_modules/axe-core/axe.min.js", import.meta.url),
20	  "utf8"
21	);
22	
23	const args = parseArgs();
24	const SKIP = args.skippreload ? "skippreload" : "";
25	const onlyRoute = args.route || null;
26	
27	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
28	
29	// ---- check() harness -------------------------------------------------------
30	const results = [];
31	function check(name, ok, info = "") {
32	  results.push({ name, ok: !!ok, info });
33	  console.log(`${ok ? "PASS" : "FAIL"} ${name}${info ? `  ${info}` : ""}`);
34	}
35	
36	// Any of these fetched while reduced-motion / mobile / a no-GL route is active
37	// is a chunk-gating leak (scar #10 + perf budget). Matches Vite dep-optimized
38	// paths and any future manual GL chunk names.
39	const GL_CHUNKS =
40	  /node_modules\/\.vite\/deps\/(three|@react-three|postprocessing)|node_modules\/(three|@react-three|postprocessing)|\b(three|drei|HeroCanvas|GLStage|webgl|PipelineScene|[A-Za-z]*Scene)[-.][\w]+\.js/i;
41	
42	// Draw-call measurement: composer passes are only counted with autoReset off,
43	// accumulated across ~10 ticks then averaged (autoReset-on reports just the
44	// final screen-quad pass == 1). Returns -1 when no GL context (window.__gl).
45	async function measureDrawCalls(page) {
46	  return page.evaluate(
47	    () =>
48	      new Promise((res) => {
49	        const gl = window.__gl;
50	        if (!gl) return res(-1);
51	        gl.info.autoReset = false;
52	        gl.info.reset();
53	        if (window.__frame) window.__frame.needsFrames = 30;
54	        let ticks = 0;
55	        const tick = () => {
56	          if (++ticks < 10) return requestAnimationFrame(tick);
57	          const avg = Math.round(gl.info.render.calls / ticks);
58	          gl.info.autoReset = true;
59	          res(avg);
60	        };
61	        requestAnimationFrame(tick);
62	      })
63	  );
64	}
65	
66	// ScrollTrigger count, or -1 when the page hasn't exposed window.__stCount yet
67	// (current site does not). Callers skip gracefully on -1.
68	function stCount(page) {
69	  return page.evaluate(() => (window.__stCount ? window.__stCount() : -1));
70	}
71	
72	const EXEC = await resolveChrome();
73	const browser = await chromium.launch({ executablePath: EXEC, headless: true });
74	
75	const routes = ROUTES.filter((r) => !onlyRoute || r.path === onlyRoute);
76	if (routes.length === 0) {
77	  console.error(`No ROUTES match --route=${onlyRoute}`);
78	  process.exit(2);
79	}
80	
81	for (const route of routes) {
82	  const url = DEV_URL + route.path + (SKIP ? (route.path.includes("?") ? "&" : "?") + SKIP : "");
83	
84	  // ---- DESKTOP pass: load clean, audit links/integrations, GL on showpiece --
85	  {
86	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
87	    const consoleErrors = [];
88	    const pageErrors = [];
89	    const requests = [];
90	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
91	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 300)));
92	    page.on("request", (r) => requests.push(r.url()));
93	
94	    let emailjsReq = null;
95	    await page.route("**/api.emailjs.com/**", (r) => {
96	      const req = r.request();
97	      // Keep the FULL post body — service/template ids live deep inside the
98	      // multipart form-data, well past any fixed slice. Slice only for display.
99	      emailjsReq = { url: req.url(), method: req.method(), post: req.postData() || "" };
100	      r.fulfill({ status: 200, body: "OK" });
101	    });
102	
103	    await page.goto(url, { waitUntil: "load", timeout: 60000 });
104	    await sleep(3500);
105	
106	    const tag = `[${route.name}]`;
107	
108	    // Nav links present.
109	    const navCount = await page.evaluate(
110	      () => document.querySelectorAll("nav a, nav button").length
111	    );
112	    check(`${tag} nav links present`, navCount >= 5, `(${navCount})`);
113	
114	    // Link / integration audit.
115	    const links = await page.evaluate(() => ({
116	      linkedinMembers: document.querySelectorAll('a[href*="linkedin.com/in/"]').length,
117	      linkedinCompany: document.querySelectorAll('a[href*="linkedin.com/company/"]').length,
118	      calendly: document.querySelectorAll('a[href*="calendly.com/sachmeet-kartar/30min"]').length,
119	      mailto: document.querySelectorAll('a[href="mailto:hello@kartar.ai"]').length,
120	      sender:
121	        !!document.querySelector('[data-sender-form-id]') ||
122	        !!document.querySelector('#sender-form'),
123	      fields: {
124	        from_name: !!document.querySelector('[name="from_name"]'),
125	        from_email: !!document.querySelector('[name="from_email"]'),
126	        from_phone: !!document.querySelector('[name="from_phone"]'),
127	        message: !!document.querySelector('[name="message"]'),
128	      },
129	    }));
130	    check(`${tag} 18 LinkedIn member links`, links.linkedinMembers === 18, `(${links.linkedinMembers})`);
131	    check(`${tag} >=1 company LinkedIn`, links.linkedinCompany >= 1, `(${links.linkedinCompany})`);
132	    check(`${tag} >=3 Calendly links`, links.calendly >= 3, `(${links.calendly})`);
133	    check(`${tag} mailto hello@kartar.ai`, links.mailto >= 1);
134	    check(`${tag} Sender form mount present`, links.sender);
135	    check(
136	      `${tag} EmailJS fields present`,
137	      links.fields.from_name && links.fields.from_email && links.fields.from_phone && links.fields.message,
138	      `(name=${links.fields.from_name} email=${links.fields.from_email} phone=${links.fields.from_phone} msg=${links.fields.message})`
139	    );
140	
141	    // EmailJS stub-submit: fill + submit, assert the request is formed with the
142	    // right service/template ids and the success text appears. Never sent — the
143	    // api.emailjs.com route is intercepted and fulfilled with OK.
144	    const hasContact = await page.evaluate(() => !!document.querySelector('form [name="from_name"]'));
145	    if (hasContact) {
146	      await page.evaluate(() => {
147	        const el = document.querySelector('form [name="from_name"]')?.closest("section") || document.querySelector("#contact");
148	        if (!el) return;
149	        const top = el.getBoundingClientRect().top + (window.__lenis ? window.__lenis.scroll : window.scrollY);
150	        if (window.__lenis) window.__lenis.scrollTo(top, { immediate: true });
151	        else window.scrollTo(0, top);
152	      });
153	      await sleep(1000);
154	      await page.fill('[name="from_name"]', "Verification Bot");
155	      await page.fill('[name="from_email"]', "verify@example.com");
156	      await page.fill('[name="from_phone"]', "+91 00000 00000");
157	      await page.fill('[name="message"]', "Automated verification - not a real enquiry.");
158	      await page.click('form button[type="submit"]');
159	      await sleep(2500);
160	
161	      check(
162	        `${tag} EmailJS request formed (stubbed)`,
163	        !!emailjsReq,
164	        emailjsReq ? `→ ${emailjsReq.method} ${emailjsReq.url.slice(0, 50)}` : ""
165	      );
166	      const post = emailjsReq?.post || "";
167	      check(
168	        `${tag} EmailJS service_gtn59h8 in request`,
169	        post.includes("service_gtn59h8"),
170	        post ? "" : "(no post body captured)"
171	      );
172	      check(
173	        `${tag} EmailJS template_2l3bp6f in request`,
174	        post.includes("template_2l3bp6f"),
175	        post ? "" : "(no post body captured)"
176	      );
177	      const success = await page.evaluate(() =>
178	        document.body.innerText.includes("Message sent. We'll get back to you within 24 hours.")
179	      );
180	      check(`${tag} success message shown`, success);
181	    }
182	
183	    // GL chunk-gating on desktop: a route with NO showpiece must never fetch GL
184	    // chunks. (A showpiece route legitimately may — checked only on reduced/mobile.)
185	    if (!route.showpiece) {
186	      const leaked = requests.filter((u) => GL_CHUNKS.test(u));
187	      check(`${tag} no GL chunks on no-showpiece route (desktop)`, leaked.length === 0, leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : "");
188	    } else {
