1	// facts_check.mjs — site-wide FACTS PRESENCE gate.
2	//
3	// Loads the pinned facts contract (plans/00-facts/facts.json), crawls EVERY
4	// ROUTES entry against the live dev server, accumulates rendered text + hrefs +
5	// form internals + page HTML across ALL routes combined, then asserts that each
6	// pinned fact appears SOMEWHERE on the site. This is a presence check, not a
7	// per-route or wording check: prose may be freely rewritten, but the pinned
8	// strings (LinkedIn URLs, stats, stage labels, ids, etc.) must survive.
9	//
10	// Codes against the SCHEMA in conventions — never assumes the file's prose.
11	//
12	// Usage: node scripts/qa/facts_check.mjs
13	// Exit 1 on any miss; prints a PASS/FAIL table.
14	import { chromium } from "playwright-core";
15	import fs from "fs";
16	import path from "path";
17	import { ROUTES, DEV_URL, resolveChrome, repoRoot } from "./routes.mjs";
18	
19	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
20	
21	const FACTS_PATH = path.join(repoRoot(), "plans", "00-facts", "facts.json");
22	if (!fs.existsSync(FACTS_PATH)) {
23	  console.error(`FATAL: facts contract not found at ${FACTS_PATH}`);
24	  console.error("This file is authored in parallel (Sprint 01 / facts extraction).");
25	  process.exit(2);
26	}
27	let facts;
28	try {
29	  facts = JSON.parse(fs.readFileSync(FACTS_PATH, "utf8"));
30	} catch (e) {
31	  console.error(`FATAL: facts.json is not valid JSON: ${e.message}`);
32	  process.exit(2);
33	}
34	
35	// Safe getters — the contract is authored elsewhere; tolerate partial files by
36	// skipping checks whose source data is absent rather than crashing.
37	const arr = (v) => (Array.isArray(v) ? v : []);
38	const str = (v) => (typeof v === "string" ? v : "");
39	
40	const EXEC = await resolveChrome();
41	const browser = await chromium.launch({ executablePath: EXEC, headless: true });
42	
43	// Accumulators across all routes.
44	let allText = "";
45	const allHrefs = new Set();
46	let allHtml = "";
47	const formFieldNames = new Set();
48	// Scroll-driven/lazy sections (stats, testimonials, mid-page Calendly) only
49	// render into the DOM as they enter the viewport, so a single end-of-crawl
50	// snapshot misses them. We snapshot at EVERY scroll step and union everything.
51	// Calendly anchors can repeat across sections; the contract counts anchor
52	// INSTANCES (>=3), not unique URLs, so we track the max instance count seen in
53	// any single snapshot per route and sum across routes.
54	let calendlyAnchorCount = 0;
55	
56	function absorb(data) {
57	  allText += "\n" + data.text;
58	  allHtml += "\n" + data.html;
59	  for (const h of data.hrefs) allHrefs.add(h);
60	  for (const f of data.fields) formFieldNames.add(f);
61	}
62	
63	for (const route of ROUTES) {
64	  const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
65	  await page.goto(DEV_URL + route.path + "?skippreload", { waitUntil: "load", timeout: 60000 }).catch(() => {});
66	  await sleep(3000);
67	
68	  // Capture BOTH innerText (visible) and textContent (mounted but possibly
69	  // animation-hidden via opacity/visibility — innerText drops those). Scroll-
70	  // pinned sections (e.g. before/after stat swaps) only mount their text at a
71	  // specific scroll position, so we union across every step.
72	  const snapshot = () =>
73	    page.evaluate((calHref) => ({
74	      text: document.body.innerText + "\n" + document.body.textContent,
75	      hrefs: [...document.querySelectorAll("a[href]")].map((a) => a.getAttribute("href")),
76	      html: document.documentElement.outerHTML,
77	      fields: [...document.querySelectorAll("[name]")].map((e) => e.getAttribute("name")),
78	      calAnchors: calHref
79	        ? [...document.querySelectorAll("a[href]")].filter((a) => (a.getAttribute("href") || "").includes(calHref)).length
80	        : 0,
81	    }), str(facts.links?.calendly));
82	
83	  // Step through the page top→bottom, absorbing rendered DOM at each stop.
84	  const H = await page.evaluate(() => document.documentElement.scrollHeight);
85	  const VH = 900;
86	  const STEP = Math.round(VH * 0.7);
87	  let routeMaxCal = 0;
88	  for (let y = 0; y <= H; y += STEP) {
89	    await page.evaluate((t) => {
90	      if (window.__lenis) window.__lenis.scrollTo(t, { immediate: true });
91	      else window.scrollTo(0, t);
92	    }, Math.min(y, H));
93	    await sleep(550);
94	    const data = await snapshot();
95	    absorb(data);
96	    if (data.calAnchors > routeMaxCal) routeMaxCal = data.calAnchors;
97	  }
98	  calendlyAnchorCount += routeMaxCal;
99	
100	  // Carousels/sliders mount only their active slide (e.g. testimonials render
101	  // `items[current]`). The current testimonials <section> has NO id, so we
102	  // anchor on its label text, walk up to the enclosing <section>, and click
103	  // every nav button (the dot buttons set the slide index directly — the most
104	  // reliable way to surface every slide). Add labels here for future sliders.
105	  const sliderLabels = ["Testimonials"];
106	  for (const label of sliderLabels) {
107	    const btnCount = await page.evaluate((lbl) => {
108	      const node = [...document.querySelectorAll("*")].find(
109	        (e) => e.children.length === 0 && e.textContent.trim() === lbl
110	      );
111	      const section = node?.closest("section");
112	      window.__qaSlider = section || null;
