// facts_check.mjs — site-wide FACTS PRESENCE gate.
//
// Loads the pinned facts contract (plans/00-facts/facts.json), crawls EVERY
// ROUTES entry against the live dev server, accumulates rendered text + hrefs +
// form internals + page HTML across ALL routes combined, then asserts that each
// pinned fact appears SOMEWHERE on the site. This is a presence check, not a
// per-route or wording check: prose may be freely rewritten, but the pinned
// strings (LinkedIn URLs, stats, stage labels, ids, etc.) must survive.
//
// Codes against the SCHEMA in conventions — never assumes the file's prose.
//
// Usage: node scripts/qa/facts_check.mjs
// Exit 1 on any miss; prints a PASS/FAIL table.
import { chromium } from "playwright-core";
import fs from "fs";
import path from "path";
import { ROUTES, DEV_URL, resolveChrome, repoRoot } from "./routes.mjs";

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

const FACTS_PATH = path.join(repoRoot(), "plans", "00-facts", "facts.json");
if (!fs.existsSync(FACTS_PATH)) {
  console.error(`FATAL: facts contract not found at ${FACTS_PATH}`);
  console.error("This file is authored in parallel (Sprint 01 / facts extraction).");
  process.exit(2);
}
let facts;
try {
  facts = JSON.parse(fs.readFileSync(FACTS_PATH, "utf8"));
} catch (e) {
  console.error(`FATAL: facts.json is not valid JSON: ${e.message}`);
  process.exit(2);
}

// Safe getters — the contract is authored elsewhere; tolerate partial files by
// skipping checks whose source data is absent rather than crashing.
const arr = (v) => (Array.isArray(v) ? v : []);
const str = (v) => (typeof v === "string" ? v : "");

const EXEC = await resolveChrome();
const browser = await chromium.launch({ executablePath: EXEC, headless: true });

// Accumulators across all routes.
let allText = "";
const allHrefs = new Set();
let allHtml = "";
const formFieldNames = new Set();
// Scroll-driven/lazy sections (stats, testimonials, mid-page Calendly) only
// render into the DOM as they enter the viewport, so a single end-of-crawl
// snapshot misses them. We snapshot at EVERY scroll step and union everything.
// Calendly anchors can repeat across sections; the contract counts anchor
// INSTANCES (>=3), not unique URLs, so we track the max instance count seen in
// any single snapshot per route and sum across routes.
let calendlyAnchorCount = 0;

function absorb(data) {
  allText += "\n" + data.text;
  allHtml += "\n" + data.html;
  for (const h of data.hrefs) allHrefs.add(h);
  for (const f of data.fields) formFieldNames.add(f);
}

for (const route of ROUTES) {
  const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
  await page.goto(DEV_URL + route.path + "?skippreload", { waitUntil: "load", timeout: 60000 }).catch(() => {});
  await sleep(3000);

  // Capture BOTH innerText (visible) and textContent (mounted but possibly
  // animation-hidden via opacity/visibility — innerText drops those). Scroll-
  // pinned sections (e.g. before/after stat swaps) only mount their text at a
  // specific scroll position, so we union across every step.
  const snapshot = () =>
    page.evaluate((calHref) => ({
      text: document.body.innerText + "\n" + document.body.textContent,
      hrefs: [...document.querySelectorAll("a[href]")].map((a) => a.getAttribute("href")),
      html: document.documentElement.outerHTML,
      fields: [...document.querySelectorAll("[name]")].map((e) => e.getAttribute("name")),
      calAnchors: calHref
        ? [...document.querySelectorAll("a[href]")].filter((a) => (a.getAttribute("href") || "").includes(calHref)).length
        : 0,
    }), str(facts.links?.calendly));

  // Step through the page top→bottom, absorbing rendered DOM at each stop.
  const H = await page.evaluate(() => document.documentElement.scrollHeight);
  const VH = 900;
  const STEP = Math.round(VH * 0.7);
  let routeMaxCal = 0;
  for (let y = 0; y <= H; y += STEP) {
    await page.evaluate((t) => {
      if (window.__lenis) window.__lenis.scrollTo(t, { immediate: true });
      else window.scrollTo(0, t);
    }, Math.min(y, H));
    await sleep(550);
    const data = await snapshot();
    absorb(data);
    if (data.calAnchors > routeMaxCal) routeMaxCal = data.calAnchors;
  }
  calendlyAnchorCount += routeMaxCal;

  // Carousels/sliders mount only their active slide (e.g. testimonials render
  // `items[current]`). The current testimonials <section> has NO id, so we
  // anchor on its label text, walk up to the enclosing <section>, and click
  // every nav button (the dot buttons set the slide index directly — the most
  // reliable way to surface every slide). Add labels here for future sliders.
  const sliderLabels = ["Testimonials"];
  for (const label of sliderLabels) {
    const btnCount = await page.evaluate((lbl) => {
      const node = [...document.querySelectorAll("*")].find(
        (e) => e.children.length === 0 && e.textContent.trim() === lbl
      );
      const section = node?.closest("section");
      window.__qaSlider = section || null;
      return section ? section.querySelectorAll("button").length : 0;
    }, label);
    if (!btnCount) continue;
    // Scroll the section into view so its buttons are interactable.
    await page.evaluate(() => {
      const el = window.__qaSlider;
      if (!el) return;
      const y = el.getBoundingClientRect().top + (window.__lenis ? window.__lenis.scroll : window.scrollY) - 100;
      if (window.__lenis) window.__lenis.scrollTo(y, { immediate: true });
      else window.scrollTo(0, y);
    });
    await sleep(400);
    // Click every nav button once; snapshot between clicks to absorb each slide.
    for (let k = 0; k < btnCount; k++) {
      await page.evaluate((idx) => {
        window.__qaSlider?.querySelectorAll("button")[idx]?.click();
      }, k);
      await sleep(350);
      absorb(await snapshot());
    }
  }

  await page.close();
}
await browser.close();

const hrefArr = [...allHrefs];
const hrefBlob = hrefArr.join("\n");
// Source presence: emailjs ids are wired in JS (sendForm args), so they may not
// appear in rendered text. Fall back to scanning the served module graph.
const root = repoRoot();
let sourceBlob = "";
for (const f of ["src/components/ContactForm.jsx", "src/components/Footer.jsx"]) {
  const p = path.join(root, f);
  if (fs.existsSync(p)) sourceBlob += "\n" + fs.readFileSync(p, "utf8");
}

// ---- check harness ---------------------------------------------------------
const rows = [];
function check(label, ok, info = "") {
  rows.push({ label, ok: !!ok, info });
}
const inText = (s) => s && allText.includes(s);
const inHtml = (s) => s && (allHtml.includes(s) || allText.includes(s));
const inHrefs = (s) => s && hrefBlob.includes(s);
const inSource = (s) => s && sourceBlob.includes(s);
const present = (s) => inText(s) || inHtml(s) || inHrefs(s); // rendered anywhere

// 1. Brand
check("brand name", inText(str(facts.brand?.name)), str(facts.brand?.name));

// 2. Links — Calendly count, email, company LinkedIn
const minCal = facts.links?.minCalendlyOccurrences ?? 3;
// Count anchor INSTANCES (the contract pins occurrences, not unique URLs).
check(`Calendly href count >= ${minCal}`, calendlyAnchorCount >= minCal, `(${calendlyAnchorCount})`);
const email = str(facts.links?.email);
check("mailto email present", inHrefs(`mailto:${email}`) || inText(email), email);
check("company LinkedIn present", inHrefs(str(facts.links?.linkedinCompany)), str(facts.links?.linkedinCompany));

// 3. EmailJS ids + field names (ids live in JS wiring → check rendered OR source)
const ej = facts.emailjs || {};
check("EmailJS service id", present(str(ej.service)) || inSource(str(ej.service)), str(ej.service));
check("EmailJS template id", present(str(ej.template)) || inSource(str(ej.template)), str(ej.template));
check("EmailJS public key", present(str(ej.publicKey)) || inSource(str(ej.publicKey)), str(ej.publicKey));
for (const field of arr(ej.fields)) {
  check(`EmailJS field "${field}"`, formFieldNames.has(field) || inSource(`name="${field}"`), field);
}
if (str(ej.successText)) check("EmailJS success text wired", inSource(str(ej.successText)) || inText(str(ej.successText)), str(ej.successText).slice(0, 30) + "…");

// 4. Sender form id
const senderId = str(facts.sender?.formId);
check("Sender form id present", senderId && (allHtml.includes(senderId) || inSource(senderId)), senderId);

// 5. 18 exact LinkedIn member URLs
const team = arr(facts.team);
let teamHit = 0;
for (const m of team) {
  const url = str(m.linkedin);
  if (url && inHrefs(url)) teamHit++;
}
check(`18 team LinkedIn URLs present`, team.length > 0 && teamHit === team.length, `(${teamHit}/${team.length})`);

// 6. 9 industryAgents.stat strings
const ia = arr(facts.industryAgents);
let statHit = 0;
for (const a of ia) if (inText(str(a.stat))) statHit++;
check(`9 industry stats present`, ia.length > 0 && statHit === ia.length, `(${statHit}/${ia.length})`);

// 7. 5 pipeline stage labels
const stages = arr(facts.pipeline?.stages);
let stageHit = 0;
for (const s of stages) if (inText(str(s))) stageHit++;
check(`5 pipeline stage labels present`, stages.length > 0 && stageHit === stages.length, `(${stageHit}/${stages.length})`);

// 8. 4 process step titles
const proc = arr(facts.process);
let procHit = 0;
for (const p of proc) if (inText(str(p.title))) procHit++;
check(`4 process titles present`, proc.length > 0 && procHit === proc.length, `(${procHit}/${proc.length})`);

// 9. 3 testimonial role attributions
const tests = arr(facts.testimonials);
let testHit = 0;
for (const t of tests) if (inText(str(t.role))) testHit++;
check(`3 testimonial roles present`, tests.length > 0 && testHit === tests.length, `(${testHit}/${tests.length})`);

// 10. services titles
const svc = arr(facts.services);
let svcHit = 0;
for (const s of svc) if (inText(str(s.title))) svcHit++;
check(`services titles present`, svc.length > 0 && svcHit === svc.length, `(${svcHit}/${svc.length})`);

// 11. caseStudies titles
const cs = arr(facts.caseStudies);
let csHit = 0;
for (const c of cs) if (inText(str(c.title))) csHit++;
check(`case study titles present`, cs.length > 0 && csHit === cs.length, `(${csHit}/${cs.length})`);

// 12. logoIndustries 8 words
const logos = arr(facts.logoIndustries);
let logoHit = 0;
for (const l of logos) if (inText(str(l))) logoHit++;
check(`8 logo industries present`, logos.length > 0 && logoHit === logos.length, `(${logoHit}/${logos.length})`);

// ---- print table -----------------------------------------------------------
const pad = (s, n) => (s + " ".repeat(n)).slice(0, n);
console.log("\nFACTS PRESENCE (site-wide)\n" + "=".repeat(60));
for (const r of rows) {
  console.log(`${r.ok ? "PASS" : "FAIL"}  ${pad(r.label, 34)} ${r.info || ""}`);
}
const fails = rows.filter((r) => !r.ok);
console.log("=".repeat(60));
console.log(`${rows.length - fails.length}/${rows.length} facts present`);
if (fails.length) {
  console.log("\nMISSING:");
  for (const f of fails) console.log(`  - ${f.label}  ${f.info || ""}`);
}
process.exit(fails.length ? 1 : 0);

